args.sparql:
SELECT ?game ?gameLabel
WHERE {
  ?game wdt:P31 wd:Q7889;
        rdfs:label ?gameLabel;
        wdt:P577 ?date.
  FILTER (langMatches(lang(?gameLabel), "en"))
  FILTER (CONTAINS(LCASE(?gameLabel), "elite task force"))
  FILTER (YEAR(?date) = 1996)
  SERVICE wikibase:label { bd:serviceParam wikibase:language "en". }
}

